import { useEffect } from 'react';
import { Outlet } from 'react-router-dom';
import AppCanvas from '../components/AppCanvas.jsx';
import { useAuth } from '../context/AuthContext.jsx';
import { useConfirm } from '../context/ConfirmContext.jsx';
import { protocolToThemeClass, useTheme } from '../context/ThemeContext.jsx';

const NAV_ITEMS = [
  { to: '/paciente', end: true, icon: 'ŌŚÉ', label: 'Hoje' },
  { to: '/paciente/historico', icon: 'Ōś░', label: 'Hist├│rico' },
  { to: '/paciente/calendario', icon: 'Ō¢”', label: 'Calend├Īrio' }
];

export default function PatientLayout() {
  const { session, logout } = useAuth();
  const { setThemeClass } = useTheme();
  const confirm = useConfirm();

  useEffect(() => {
    setThemeClass(protocolToThemeClass(session.protocolo));
    return () => setThemeClass('');
  }, [session.protocolo, setThemeClass]);

  const handleLogout = async () => {
    const ok = await confirm({ title: 'Encerrar sess├Żo', description: 'Tem certeza que deseja sair?', confirmLabel: 'Sair' });
    if (ok) logout();
  };

  return (
    <AppCanvas mark="Ō£¦" navItems={NAV_ITEMS} onLogout={handleLogout}>
      <Outlet />
    </AppCanvas>
  );
}
